final:
module temperature_comparator (
    input [3:0] A,
    input [3:0] B,
    output reg [1:0] result
);
  wire [3:0] _tap_A = A & {4{1'b1}};


always @(*) begin
    if (A < B)
        result = 2'b00; // A < B
    else if (A == B)
        result = 2'b01; // A = B
    else
        result = 2'b10; // A > B
end

endmodule
